const e=`{% block sw_settings_listing_option_general_info %} <mt-card :title="$t('sw-settings-listing.base.general.title')" position-identifier="sw-settings-listing-option-general-info" > {% block sw_settings_listing_option_general_info_container %} <sw-container columns="1fr 1fr" gap="0 20px" > {% block sw_settings_listing_option_general_info_name %} <mt-text-field v-model="sortingOption.label" class="sw-settings-listing-edit__general-input" :label="$t('sw-settings-listing.base.general.labelName')" :placeholder="$t('sw-settings-listing.base.general.placeholderName')" :required="true" :error="labelError" /> {% endblock %} {% block sw_settings_listing_option_general_info_technical_name %} <mt-text-field v-model="sortingOption.key" name="sw-field--listing-option-technicalName" class="sw-settings-listing-option-general-info__field-technical-name" required :label="$t('sw-settings-listing.base.general.labelTechnicalName')" :placeholder="$t('sw-settings-listing.base.general.placeholderTechnicalName')" :error="technicalNameError" :help-text="$t('sw-settings-listing.base.general.helpTextTechnicalName')" /> {% endblock %} {% block sw_settings_listing_option_general_info_active %} <mt-switch v-model="sortingOption.active" v-tooltip="{ showDelay: 300, message: $t('sw-cms.elements.productListing.config.sorting.defaultSortingCantBeDisabled'), disabled: !isDefaultSorting }" :disabled="isDefaultSorting" class="sw-settings-listing-edit__general-input" :bordered="true" :label="$t('sw-settings-listing.base.general.labelActive')" /> {% endblock %} </sw-container> {% endblock %} </mt-card> {% endblock %}`,t={template:e,props:{sortingOption:{type:Object,required:!0},isDefaultSorting:{type:Boolean,required:!0},technicalNameError:{type:Object,required:!1,default:{}},labelError:{type:Object,required:!1,default:{}}}};export{t as default};
